{
  "context": {
    "networkId": "{{domain}}",
    "version": "{{version}}",
    "action": "confirm",
    "bapId": "{{bap_id}}",
    "bapUri": "{{bap_host_root}}/bap/receiver",
    "bppId": "{{bpp_id}}",
    "bppUri": "{{bpp_host_root}}/bpp/receiver",
    "transactionId": "{{transaction_id}}",
    "messageId": "{{$guid}}",
    "timestamp": "{{iso_date}}",
    "schemaContext": ["https://raw.githubusercontent.com/beckn/DDM/main/specification/schema/DatasetItem/v1/context.jsonld"]
  },
  "message": {
    "contract": {
      "id": "770e9500-f30c-52e5-b827-557766551301",
      "descriptor": {
        "name": "Retail Tariff Policy Subscription",
        "shortDesc": "MeraShehar DISCOM subscribing to MERC retail tariff orders under public-disclosure norms"
      },
      "status": {
        "code": "ACTIVE"
      },
      "commitments": [
        {
          "id": "commitment-tariff-policy-001",
          "status": {
            "descriptor": {
              "code": "ACTIVE"
            }
          },
          "resources": [
            {
              "id": "ds-tariff-policy-mum-res-2024-25",
              "descriptor": {
                "name": "Mumbai Residential Telescopic Tariff 2024-25"
              },
              "quantity": {
                "unitText": "policy",
                "unitCode": "EA",
                "value": "1"
              }
            }
          ],
          "offer": {
            "id": "offer-tariff-policy-inline",
            "descriptor": {
              "name": "Inline Tariff Policy Delivery - Mumbai Residential 2024-25"
            },
            "resourceIds": ["ds-tariff-policy-mum-res-2024-25"]
          },
          "commitmentAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/DDM/main/specification/schema/DatasetItem/v1/context.jsonld",
            "@type": "DatasetItem",
            "schema:identifier": "ds-tariff-policy-mum-res-2024-25",
            "schema:name": "Mumbai Residential Telescopic Tariff 2024-25",
            "schema:temporalCoverage": "2024-04-01/2025-03-31",
            "dataset:accessMethod": "INLINE"
          }
        }
      ],
      "consideration": [
        {
          "id": "consideration-tariff-public-good",
          "status": {
            "code": "ACTIVE"
          },
          "considerationAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/schemas/refs/heads/main/schema/PriceSpecification/v2.1/context.jsonld",
            "@type": "PriceSpecification",
            "currency": "INR",
            "value": 0,
            "description": "Tariff orders are public regulatory artefacts — distributed at zero cost under MERC public-disclosure norms"
          }
        }
      ],
      "participants": [
        {"id": "merc-regulator-001", "descriptor": {"name": "Maharashtra Electricity Regulatory Commission"}},
        {"id": "merashehar-discom-001", "descriptor": {"name": "MeraShehar - Distribution Company"}}
      ],
      "performance": [],
      "settlements": [
        {
          "id": "settlement-tariff-no-charge",
          "considerationId": "consideration-tariff-public-good",
          "status": "COMPLETE",
          "settlementAttributes": {
            "@context": "https://raw.githubusercontent.com/beckn/schemas/refs/heads/main/schema/Payment/v2.0/context.jsonld",
            "@type": "Payment",
            "beckn:paymentStatus": "COMPLETED",
            "beckn:amount": {
              "currency": "INR",
              "value": 0
            }
          }
        }
      ]
    }
  }
}

{
  "context": {
    "networkId": "{{domain}}",
    "version": "{{version}}",
    "action": "discover",
    "location": {
      "country": {
        "code": "IND"
      },
      "city": {
        "code": "std:022"
      }
    },
    "bapId": "{{bap_id}}",
    "bapUri": "{{bap_host_root}}/bap/receiver",
    "transactionId": "{{transaction_id}}",
    "messageId": "{{$guid}}",
    "timestamp": "{{iso_date}}",
    "schemaContext": ["https://raw.githubusercontent.com/beckn/DDM/main/specification/schema/DatasetItem/v1/context.jsonld"]
  },
  "message": {
    "intent": {
      "filters": {
        "type": "jsonpath",
        "expression": "$.catalogs[*].resources[*]",
        "_expressionExamples": [
          "// all tariff policy resources in the catalog",
          "$.catalogs[*].resources[?(@.descriptor.name =~ /Tariff/)]",
          "// active offers for tariff policies",
          "$.catalogs[*] ? (exists(@.offers[*].validity.endDate >= '2025-03-31T00:00:00Z'))"
        ]
      }
    }
  }
}

